'use client'
import axios from 'axios'
import { useRouter } from 'next/navigation'
import React, { useRef, useState } from 'react'
export default function page() {
  const router = useRouter
  const [loader,setLoader] = useState(false)
  const nameRef = useRef(null);
  const slugRef = useRef(null);
  
  function createSlug(text) {
    return text
      .toLowerCase()
      .trim()
      .replace(/[^\w\s-]/g, "")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-");
  }
  
  function getSlug() {
    let value = nameRef.current.value;
    slugRef.current.value = createSlug(value);
  }
  
  const submitHandler = (e) => {
    e.preventDefault();
    setLoader(true)
    const payload = {
      name : nameRef.current.value,
      slug : slugRef.current.value
    }

    axios.post("http://localhost:5000/api/category/create",payload).then(
      (response)=>{
        if(response.data.success){
          router("/category")
        }
      }
    ).catch(
      (error)=>{
        console.log(error)
      }
    ).finally(
      ()=>{
        setLoader(false)
      }
    )
  e.target.reset()
    
  };


    

  return (
    <div className="p-6 bg-gray-50 min-h-screen flex justify-center items-start">
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow border p-8">
        {/* Header */}
        <div className="mb-6">
          <h2 className="text-2xl font-semibold text-gray-800">
            Add New Category
          </h2>
          <p className="text-sm text-gray-500 mt-1">
            Fill in the details to create a new category
          </p>
        </div>

        {/* Form */}
        <form onSubmit={submitHandler} className="space-y-5">
          {/* Category Name */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Category Name
            </label>
            <input
            onChange={getSlug}
              type="text"
              ref={nameRef}
              placeholder="Enter category name"
              className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-orange-400 outline-none"
            />
          </div>

          {/* Slug */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Slug
            </label>
            <input
              type="text"
              ref={slugRef}
              placeholder="enter-slug"
              className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-orange-400 outline-none"
            />
          </div>


          {/* Actions */}
          <div className="flex items-center justify-end gap-3 pt-4">
            <button
              type="button"
              className="px-5 py-2.5 rounded-xl border text-gray-600 hover:bg-gray-100 transition"
            >
              Cancel
            </button>

            <button
              type="submit"
              className="px-6 py-2.5 bg-orange-500 text-white rounded-xl hover:scale-105 shadow transition"
            >
              {loader ? "wait..." : "save"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );

}
